  "critical_findings": [
    {
      "title": "Off-by-one error: page 1 returns page 2 results",
      "risk": "Every caller using the documented 1-indexed API (page=1) gets `OFFSET pageSize` instead of `OFFSET 0`, silently skipping the customer's most recent orders. Page 1 shows what should be page 2. No error is raised — data just looks wrong.",
      "severity": "Critical",
      "location": "getOrderHistory, line: `const offset = page * pageSize`",
      "reproduction": "Call `getOrderHistory('cust_1', 1, 10)`. Expected: rows 0-9 (most recent 10 orders). Actual: rows 10-19. The first page of every customer's order history is unreachable through the documented API.",
      "fix": "Change to `const offset = (page - 1) * pageSize;`",
      "time_to_fix": "< 5 minutes",
      "acceptance_criteria_affected": "Any acceptance criterion involving 'view order history' or 'first page of results' — customers will see wrong orders on every page."
    },
    {
      "title": "No input validation allows negative offset, zero pageSize, and unbounded queries",
      "risk": "Negative `page` or `pageSize` values produce negative OFFSET/LIMIT which is undefined behavior in some DB drivers or returns empty/full table. A `pageSize` of 0 returns nothing. A `pageSize` of 1000000 dumps the entire table in one query, enabling denial-of-service or data scraping.",
      "severity": "High",
      "location": "getOrderHistory, function parameters",
      "reproduction": "Call `getOrderHistory('cust_1', -1, 10)` — produces `OFFSET -10`. Call `getOrderHistory('cust_1', 1, 999999)` — returns up to ~1M rows in a single query.",
      "fix": "Add guard clauses: `if (page < 1) page = 1; pageSize = Math.min(Math.max(pageSize, 1), 100);` — clamp page to >=1 and pageSize to a sane range.",
      "time_to_fix": "< 10 minutes",
      "acceptance_criteria_affected": "API robustness, rate limiting, and data exfiltration prevention."
    }
  ],

  "important_issues": [
    {
      "title": "SELECT * returns all columns including potentially sensitive data",
